    pub async fn fetch_web_endpoint(&mut self, mut method: Value, mut endpointMethod: Value, mut returnAsJson: Value, optional_args: &[Value]) -> Value {
        let mut startRegex = get_arg(optional_args, 0, Value::Null);
        let mut endRegex = get_arg(optional_args, 1, Value::Null);
        let mut errorMessage: Value = Value::Str("".to_string());
        let mut options: Value = self.safe_value(self.options.clone(), method.clone(), &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut muteOnFailure: Value = self.safe_bool_k(options.clone(), "webApiMuteFailure", &[Value::Bool(true)]);
        {
            // if it was not explicitly disabled, then don't fetch
            if !is_equal(&self.safe_bool_k(options.clone(), "webApiEnable", &[Value::Bool(true)]), &Value::Bool(true)) {
                return Value::Null;
            }
            let mut maxRetries: Value = self.safe_value_k(options.clone(), "webApiRetries", &[Value::Int(10)]);
            let mut response: Value = Value::Null;
            let mut retry: Value = Value::Int(0);
            let mut shouldBreak: Value = Value::Bool(false);
            while is_less_than(&retry, &maxRetries) {
                {
                    response = self.call_method(endpointMethod.clone(), &[Value::Map({
                        let mut m = indexmap::IndexMap::new();
                        m
                    })]).await;
                    shouldBreak = Value::Bool(true);
                    break;
                }
                if is_true(&shouldBreak) {
                    break;
                }
            }
            let mut content: Value = response.clone();
            if !is_equal(&startRegex, &Value::Null) {
                let mut splitted_by_start: Value = split(&content, &startRegex);
                content = get_value(&splitted_by_start, &Value::Int(1)); // we need second part after start
            }
            if !is_equal(&endRegex, &Value::Null) {
                let mut splitted_by_end: Value = split(&content, &endRegex);
                content = get_value(&splitted_by_end, &Value::Int(0)); // we need first part after start
            }
            if is_true(&returnAsJson) && is_true(&(is_string(&content))) {
                let mut jsoned: Value = self.parse_json_value(trim(&content)); // content should be trimmed before json parsing
                if is_true(&jsoned) {
                    return jsoned;
                }  else {
                    panic!("{}", crate::exchange_errors::bad_response(Value::Str("could not parse the response into json".to_string())));
                }
            }  else {
                return content;
            }
        }
        if is_true(&muteOnFailure) {
            return Value::Null;
        }  else {
            panic!("{}", crate::exchange_errors::bad_response(errorMessage));
        }
}

